import React from "react";
import { Star, Quote } from "lucide-react";

// ─── TESTIMONIAL DATA ────────────────────────────────────────────────────────
// Replace these placeholders with real client quotes once collected.
const featuredTestimonial = {
  quote:
    "Justin and his team treated our home renovation like it was a multi-million dollar project. Every detail considered, every deadline met, every dollar accounted for. We've never worked with a contractor this organized.",
  name: "Sarah & Michael Thompson",
  location: "Mississauga, ON",
  project: "Full Home Renovation",
  rating: 5,
};

const testimonials = [
  {
    quote:
      "From day one, the site was kept spotless. The crew showed up on time, every day. After hearing horror stories from friends, this was a revelation.",
    name: "David Chen",
    location: "Oakville, ON",
    project: "Kitchen Remodel",
    rating: 5,
  },
  {
    quote:
      "The millwork in our living room is honestly better than what we saw in the showrooms we visited. The craftsmanship speaks for itself.",
    name: "Jennifer Rossi",
    location: "Toronto, ON",
    project: "Living Room Build-Out",
    rating: 5,
  },
  {
    quote:
      "Justin was on-site nearly every day and answered every text within an hour. After dealing with other contractors who ghosted us mid-project, this was night and day.",
    name: "Mark Patel",
    location: "Vaughan, ON",
    project: "Basement Conversion",
    rating: 5,
  },
];

// ─── HELPERS ─────────────────────────────────────────────────────────────────
const getInitials = (name) =>
  name
    .replace(/&/g, "")
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((w) => w[0])
    .join("")
    .toUpperCase();

const StarRow = ({ count = 5, size = 14 }) => (
  <div className="flex items-center gap-0.5">
    {Array.from({ length: count }).map((_, i) => (
      <Star
        key={i}
        size={size}
        fill="#C9802A"
        strokeWidth={0}
        style={{ color: "#C9802A" }}
      />
    ))}
  </div>
);

// ─── MAIN EXPORT ─────────────────────────────────────────────────────────────
export default function Testimonials() {
  return (
    <section
      id="testimonials"
      data-testid="testimonials-section"
      className="py-28 md:py-40"
      style={{ backgroundColor: "#F5F2EE" }}
    >
      <div className="max-w-7xl mx-auto px-6 md:px-10">

        {/* Section header */}
        <div className="mb-16 md:mb-24 flex flex-col md:flex-row md:items-end md:justify-between gap-8">
          <div className="reveal max-w-2xl">
            <div className="flex items-center gap-3 mb-6">
              <span className="block w-10 h-px bg-brand-accent" />
              <span
                className="text-xs tracking-[0.28em] uppercase font-medium"
                style={{ color: "#8A7D6B" }}
              >
                Client Testimonials
              </span>
            </div>
            <h2
              className="font-display text-4xl md:text-5xl lg:text-6xl font-medium tracking-tighter leading-[1.05]"
              style={{ color: "#1A1A1A" }}
            >
              Trusted by{" "}
              <span style={{ color: "#A09080" }}>homeowners</span>
              <br className="hidden md:block" /> across the GTA.
            </h2>
          </div>

          {/* Aggregate trust bar */}
          <div className="reveal flex flex-col items-start md:items-end gap-2">
            <StarRow size={18} />
            <p className="text-sm font-medium" style={{ color: "#1A1A1A" }}>
              5.0 average across all client reviews
            </p>
            <p
              className="text-xs uppercase tracking-[0.2em]"
              style={{ color: "#A09080" }}
            >
              Verified Project Owners
            </p>
          </div>
        </div>

        {/* ── Featured testimonial (hero quote) ───────────────────── */}
        <div
          className="reveal relative mb-12 md:mb-16 p-10 md:p-16 lg:p-20 overflow-hidden"
          style={{ backgroundColor: "#FFFFFF", border: "1px solid #E0DCD6" }}
        >
          {/* Decorative quote mark */}
          <Quote
            size={80}
            strokeWidth={1}
            className="absolute top-8 right-8 md:top-12 md:right-12 opacity-[0.07]"
            style={{ color: "#1A1A1A", transform: "scaleX(-1)" }}
          />

          <div className="relative z-10 max-w-4xl">
            <StarRow size={18} />

            <blockquote
              className="font-display text-2xl md:text-3xl lg:text-4xl font-medium leading-[1.3] tracking-tight mt-8 mb-10"
              style={{ color: "#1A1A1A" }}
            >
              &ldquo;{featuredTestimonial.quote}&rdquo;
            </blockquote>

            <div className="flex items-center gap-5 pt-8" style={{ borderTop: "1px solid #E0DCD6" }}>
              {/* Monogram avatar */}
              <div
                className="shrink-0 w-14 h-14 rounded-full flex items-center justify-center font-display text-base font-medium"
                style={{
                  backgroundColor: "#C9802A",
                  color: "#FFFFFF",
                }}
              >
                {getInitials(featuredTestimonial.name)}
              </div>

              <div className="flex-1">
                <p className="font-medium text-base" style={{ color: "#1A1A1A" }}>
                  {featuredTestimonial.name}
                </p>
                <p
                  className="text-xs uppercase tracking-[0.2em] mt-1"
                  style={{ color: "#A09080" }}
                >
                  {featuredTestimonial.project} &middot; {featuredTestimonial.location}
                </p>
              </div>
            </div>
          </div>
        </div>

        {/* ── Testimonial grid (3 cards) ──────────────────────────── */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 md:gap-8">
          {testimonials.map((t, i) => (
            <article
              key={t.name}
              data-testid={`testimonial-card-${i}`}
              className="reveal group p-8 md:p-10 flex flex-col transition-all duration-500 hover:-translate-y-1"
              style={{
                backgroundColor: "#FFFFFF",
                border: "1px solid #E0DCD6",
              }}
            >
              {/* Stars */}
              <StarRow size={14} />

              {/* Quote */}
              <blockquote
                className="font-display text-lg leading-snug tracking-tight mt-6 mb-8 flex-1"
                style={{ color: "#2A2420" }}
              >
                &ldquo;{t.quote}&rdquo;
              </blockquote>

              {/* Attribution */}
              <div
                className="flex items-center gap-4 pt-6"
                style={{ borderTop: "1px solid #E0DCD6" }}
              >
                <div
                  className="shrink-0 w-11 h-11 rounded-full flex items-center justify-center font-display text-sm font-medium"
                  style={{
                    backgroundColor: "#EDEAE5",
                    color: "#1A1A1A",
                  }}
                >
                  {getInitials(t.name)}
                </div>
                <div className="flex-1 min-w-0">
                  <p
                    className="font-medium text-sm truncate"
                    style={{ color: "#1A1A1A" }}
                  >
                    {t.name}
                  </p>
                  <p
                    className="text-[10px] uppercase tracking-[0.18em] mt-1 truncate"
                    style={{ color: "#A09080" }}
                  >
                    {t.project}
                  </p>
                </div>
              </div>
            </article>
          ))}
        </div>

        {/* ── Bottom CTA strip ─────────────────────────────────────── */}
        <div
          className="reveal mt-16 md:mt-20 pt-10 flex flex-col md:flex-row items-start md:items-center justify-between gap-6"
          style={{ borderTop: "1px solid #DDD8D0" }}
        >
          <p
            className="font-display text-xl md:text-2xl font-medium tracking-tight max-w-lg"
            style={{ color: "#1A1A1A" }}
          >
            Your home deserves the same discipline.
          </p>
          <a
            href="#contact"
            className="group inline-flex items-center gap-3 text-xs font-bold tracking-[0.25em] uppercase transition-colors"
            style={{ color: "#C9802A" }}
          >
            Start your project
            <span
              className="block w-8 h-px transition-all duration-300 group-hover:w-12"
              style={{ backgroundColor: "#C9802A" }}
            />
          </a>
        </div>

      </div>
    </section>
  );
}
